const http = require('http');
const fs = require('fs');
const path = require('path');
const { parse } = require('querystring');

function handleFileUpload(req, res, uploadDir = './uploads') {
  if (!fs.existsSync(uploadDir)) {
    fs.mkdirSync(uploadDir, { recursive: true });
  }

  if (req.method === 'POST') {
    let body = [];
    let boundary = '';
    
    const contentType = req.headers['content-type'] || '';
    const boundaryMatch = contentType.match(/boundary=(.+)/);
    
    if (boundaryMatch) {
      boundary = '--' + boundaryMatch[1];
    }

    req.on('data', chunk => {
      body.push(chunk);
    });

    req.on('end', () => {
      const buffer = Buffer.concat(body);
      
      if (boundary) {
        parseMultipartFormData(buffer, boundary, uploadDir, (err, files) => {
          if (err) {
            res.writeHead(500, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ error: err.message }));
            return;
          }
          
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ 
            success: true, 
            files: files 
          }));
        });
      } else {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid content type' }));
      }
    });

    req.on('error', (err) => {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: err.message }));
    });
  } else {
    res.writeHead(405, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Method not allowed' }));
  }
}

function parseMultipartFormData(buffer, boundary, uploadDir, callback) {
  const files = [];
  const parts = [];
  let position = 0;

  const boundaryBuffer = Buffer.from(boundary);
  const endBoundaryBuffer = Buffer.from(boundary + '--');

  while (position < buffer.length) {
    const boundaryIndex = buffer.indexOf(boundaryBuffer, position);
    
    if (boundaryIndex === -1) break;

    const nextBoundaryIndex = buffer.indexOf(boundaryBuffer, boundaryIndex + boundaryBuffer.length);
    const endBoundaryIndex = buffer.indexOf(endBoundaryBuffer, boundaryIndex);

    let partEnd;
    if (nextBoundaryIndex === -1 && endBoundaryIndex !== -1) {
      partEnd = endBoundaryIndex;
    } else if (nextBoundaryIndex !== -1) {
      partEnd = nextBoundaryIndex;
    } else {
      break;
    }

    const partStart = boundaryIndex + boundaryBuffer.length;
    const part = buffer.slice(partStart, partEnd);
    
    if (part.length > 4) {
      parts.push(part);
    }

    position = partEnd;
  }

  parts.forEach(part => {
    const headerEnd = part.indexOf('\r\n\r\n');
    if (headerEnd === -1) return;

    const headers = part.slice(0, headerEnd).toString();
    const content = part.slice(headerEnd + 4, part.length - 2);

    const filenameMatch = headers.match(/filename="(.+?)"/);
    const nameMatch = headers.match(/name="(.+?)"/);
    
    if (filenameMatch && filenameMatch[1]) {
      const filename = filenameMatch[1];
      const sanitizedFilename = path.basename(filename);
      const timestamp = Date.now();
      const uniqueFilename = `${timestamp}_${sanitizedFilename}`;
      const filepath = path.join(uploadDir, uniqueFilename);

      try {
        fs.writeFileSync(filepath, content);
        files.push({
          fieldname: nameMatch ? nameMatch[1] : 'file',
          originalname: sanitizedFilename,
          filename: uniqueFilename,
          path: filepath,
          size: content.length
        });
      } catch (err) {
        callback(err);
        return;
      }
    }
  });

  callback(null, files);
}

module.exports = handleFileUpload;